@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    @* ── Summary stats bar ── *@
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><small class="text-muted">Total</small><strong>@_allTasks.Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">To Do</small><strong>@GetColumnTasks("To Do").Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">In Progress</small><strong>@GetColumnTasks("In Progress").Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">Done</small><strong>@GetColumnTasks("Done").Count</strong></div></div>
        <div class="col"><div class="card text-center p-2"><small class="text-muted">Overdue</small><strong class="text-danger">@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</strong></div></div>
    </div>

    @* ── Search bar ── *@
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    @* ── Kanban columns ── *@
    <div class="row g-3">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@column</strong>
                        <span class="badge bg-secondary">@GetColumnTasks(column).Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="min-height:200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <small class="text-muted">@task.Assignee</small>
                                    <div class="d-flex align-items-center justify-content-between mt-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <small>@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex justify-content-between mt-2">
                                        @if (column != _columns[0])
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[Array.IndexOf(_columns, column) - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (column != _columns[^1])
                                        {
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, _columns[Array.IndexOf(_columns, column) + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @* ── Inline add-task form ── *@
                        @if (_addingColumn == column)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2"
                                           @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="SaveNewTaskAsync">
                                            @(_saving ? "Saving…" : "Save")
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer text-center">
                        <button class="btn btn-sm btn-outline-primary"
                                @onclick="() => BeginAdd(column)"
                                disabled="@(_addingColumn is not null)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;
    private bool _moving;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status)
        => _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
        => _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchText)
                         || t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            _moving = true;
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = _allTasks[idx];
                _allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _moving = false;
        }
    }

    private void BeginAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingColumn is null) return;
        try
        {
            _saving = true;
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync returns a task with default status; override to match the target column
            _allTasks.Add(created with { Status = _addingColumn });
            if (created.Status != _addingColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingColumn);
            }
            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

